package genxsolution.vms.vmsbackend.maintenance_management.maintenance_plan.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_plan.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_plan.service.MaintenancePlanService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/vehicles/maintenance-plans") public class MaintenancePlanController { private final MaintenancePlanService service; public MaintenancePlanController(MaintenancePlanService service){this.service=service;} @GetMapping public List<MaintenancePlanResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public MaintenancePlanResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public MaintenancePlanResponse create(@RequestBody MaintenancePlanUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public MaintenancePlanResponse update(@PathVariable UUID id,@RequestBody MaintenancePlanUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
